import React, { useState } from 'react';
import { YMaps, Map, Placemark } from '@pbe/react-yandex-maps';
import locations from '../data/locations.json';
import './MapSection.css';

const MapSection = ({ language }) => {
  const [mapLoaded, setMapLoaded] = useState(false);
  
  const title = language === 'RU' ? 'Куда пойти в Тюмени?' : 'Where to go in Tyumen?';
  const subtitle = language === 'RU' ? '10 мест, которые меняют представление о городе' : '10 places that change the perception of the city';
  
  const defaultMapState = {
    center: [57.153, 65.535],
    zoom: 13,
    controls: ['zoomControl', 'fullscreenControl']
  };

  const mapCenter = [57.153, 65.535];

  const flyToLocation = (coords) => {
    if (window.ymaps) {
      window.ymaps.ready(() => {
        const mapInstance = document.querySelector('.ymaps-2-1-79-map');
        if (mapInstance && mapInstance.__map) {
          mapInstance.__map.panTo(coords, { duration: 500 });
          mapInstance.__map.setZoom(16);
        }
      });
    }
  };

  return (
    <section id="map" className="map-section section">
      <div className="container">
        <h2 className="section-title">{title}</h2>
        <p className="section-subtitle">{subtitle}</p>
        <div className="map-grid">
          <div className="map-wrapper">
            <YMaps 
              query={{ 
                apikey: 'ac507a39-333a-472a-81e9-28051014e8d8',
                lang: language === 'RU' ? 'ru_RU' : 'en_US'
              }}
            >
              <Map
                defaultState={defaultMapState}
                width="100%"
                height="100%"
                onLoad={() => setMapLoaded(true)}
              >
                {mapLoaded && locations.map((location) => (
                  <Placemark
                    key={location.id}
                    geometry={location.coords}
                    properties={{
                      hintContent: location.name,
                      balloonContentHeader: `<b>${location.icon} ${location.name}</b>`,
                      balloonContentBody: location.description,
                    }}
                    options={{
                      preset: 'islands#blueIcon',
                      openBalloonOnClick: true,
                    }}
                  />
                ))}
              </Map>
            </YMaps>
          </div>
          <div className="places-list">
            <div className="places-header">
              <span className="cyan mono">📍 geolocation_data</span>
            </div>
            <div className="places-items">
              {locations.map((location) => (
                <div
                  key={location.id}
                  className="place-item"
                  onClick={() => flyToLocation(location.coords)}
                >
                  <span className="place-icon cyan">▸</span>
                  <div className="place-info">
                    <div className="place-name">{location.icon} {location.name}</div>
                    <div className="place-desc">{location.description}</div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>
    </section>
  );
};

export default MapSection;